arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    shotTime+=1
    if shotTime>=shotDelay
    {
      var tNewAttack,tOffsetShotX;
      if image_xscale=1
        tOffsetShotX=4
      else
        tOffsetShotX=-4
      tNewAttack=instance_create(x+tOffsetShotX,y-8,oNormalBullet)
      tNewAttack.sprite_index=sOctorokRock
      tNewAttack.atkPower=atkPower
      tNewAttack.bulletSpeed=7
      tNewAttack.image_speed=0.33
      if image_xscale=1
        tNewAttack.direction=0
      else
        tNewAttack.direction=180
      shotTime=0
    }
    
    if initDir=0 //Rising
    {
      x+=flyVel
      y+=airVel
      airVel+=0.3
      if airVel>=2
      {
        xVel=flyVel
        initDir=1
      }
    }
    else
    {
      yVel+=0.3
      if isCollisionBottom(1)
      {
        yVel=0
        if initDir=1
        {
          xVel=runAcc
          if x>oPlayer1.x
            xVel*=-1
          initDir=2
        }
      }
      if isCollisionLeft(1)
        xVel=runAcc
      if isCollisionRight(1)
        xVel=-runAcc
      if isCollisionTop(1)
        yVel=0.5
      
      if xVel>0
        image_xscale=1
      else
        image_xscale=-1
      
      moveTo(xVel,yVel)
      if isCollisionSolid()
      {
        if image_xscale=1 {x+=runAcc}
        else {x-=runAcc}
      }
      
      if y>room_height+32
      {
        if questType>0
          enemyQuest(questType)
        instance_destroy()
      }
    }
  }
  enemyStepEvent()
}
